BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?name ?specName ?minName ?maxName WHERE {
  ?elem rdf:type vocab:duration%20constraint .
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(STR(?elem), "Alignment%2520and%2520Phasing") || CONTAINS(STR(?elem), "APS"))
  OPTIONAL {
    ?elem vocab:DurationConstraint_specification__from_DurationConstraint ?spec .
    ?spec vocab:NamedElement_name ?specName .
    OPTIONAL {
      ?spec vocab:DurationInterval_min__from_DurationInterval ?minVal .
      ?minVal vocab:NamedElement_name ?minName .
    }
    OPTIONAL {
      ?spec vocab:DurationInterval_max__from_DurationInterval ?maxVal .
      ?maxVal vocab:NamedElement_name ?maxName .
    }
  }
}
ORDER BY ?name
LIMIT 50

